      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
    }

    .update-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .update-header h2 i {
      color: #4e6ef2;
    }

    .update-tag {
