      color: #4e6ef2;
      padding: 4px 8px;
      border-radius: 8px;
      font-size: 0.75rem;
      font-weight: 600;
    }

    .update-content {
      padding: 16px;
    }

    .update-date {
      font-weight: 600;
      color: #4e6ef2;
      margin-bottom: 12px;
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 8px 0;
      border-bottom: 1px dashed #e0e0e0;
    }

    .update-text {
      margin: 8px 0;
      position: relative;
      padding-left: 16px;
      line-height: 1.5;
      color: var(--text-main);
      font-size: 0.95rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .update-text::before {
      content: '•';
      position: absolute;
      left: 0;
      font-weight: bold;
      color: #4e6ef2;
      font-size: 1.2rem;
      line-height: 1;
    }

    /* 历史日志 */
    .history-container {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
