      margin-bottom: 0;
      padding-bottom: 0;
    }

    .history-date {
      font-weight: 600;
      color: var(--text-main);
      margin-bottom: 8px;
      display: flex;
      align-items: center;
      gap: 4px;
      font-size: 0.9rem;
      background: rgba(78, 110, 242, 0.05);
      padding: 6px 10px;
