function login(){}

function fq_login() {
    try {
        java.startBrowserAwait("http://103.189.141.163:9587/log", "登录")
    } catch (e) {
        java.toast(e)
    }

    var cookie_ = "sessionid=" + (String(cookie.getKey("103.189.141.163", "sessionid")) ? String(cookie.getKey("103.189.141.163", "sessionid")) : source.getLoginInfoMap()['sessionid'])

    var sessionId = cookie_.replace("sessionid=", "")

    var user = ""
    try {
        var response = java.ajax("http://103.189.141.163:9587/fq?action=info&sessionid=" + sessionId)
        var data = JSON.parse(response)
        user = data.name
    } catch (e) {}

    if (!cookie_ || cookie_ == "sessionid=" || !user) {
        java.toast("未获取到登录凭据，登录失败")
        return false
    }

    java.toast("\n\n欢迎 " + user + "\n登录成功！")
    return true
}

function setmode(mode) {
    try {
        var value = JSON.parse(source.getVariable());
        value.mode = mode;
        source.setVariable(JSON.stringify(value, null, "\t"));
    } catch (error) {
        source.setVariable(JSON.stringify({"mode": mode}, null, "\t"));
    }

    var modeName = "";
    if (mode == "3") {
        modeName = "小说"
    }
    if (mode == "2") {
        modeName = "有声"
    }
    if (mode == "8") {
        modeName = "漫画"
    }
    if (mode == "11") {
        modeName = "视频"
    }

    java.longToast(modeName + "设置成功")
}

function getmode() {
    try {
        var value = JSON.parse(source.getVariable());
        var mode = value.mode;
        var modeName = "";
        if (mode == "3") {
            modeName = "小说"
        }
        if (mode == "2") {
            modeName = "有声"
        }
        if (mode == "8") {
            modeName = "漫画"
        }
        if (mode == "11") {
            modeName = "视频"
        }
        java.longToast("当前：" + modeName)
    } catch (error) {
        java.longToast("默认小说")
    }
}

