@js:
try {
    var value = JSON.parse(source.getVariable());
    var mode = value.mode;
    if (mode == "3") {
        tab = "小说"
        java.put("type", "3")
    }
    if (mode == "2") {
        tab = "有声"
        java.put("type", "2")
    }
    if (mode == "8") {
        tab = "漫画"
        java.put("type", "8")
    }
    if (mode == "11") {
        tab = "视频"
        java.put("type", "11")
    }
    if(!tab) {
        tab = "小说"
        java.put("type", "3")
    }
} catch (error) {
    tab = "小说"
    java.put("type", "3")
}

result = getHost() + '/search?q={{key}}&tab=' + tab + '&source=番茄&page={{page}}'

