function wrapContentForIOS(content) {
    const pureContent = content.trim();
    if (deviceType.call(this)) {
        return pureContent;
    }
    let lines = pureContent.split('\n').map(line => {
        if (line.trim()) {
            const trimLine = line.trim().replace(/\s+/g, ' ');
            return `<span rs-native>${trimLine}</span>`;
        }
        return line;
    });
    return lines.join('\n');
}

function buildCommentUrl(sourceType, bid, cid, para) {
    let host = getServerHost.call(this);
    let isModifiedVersion = checkEnv.call(this);
    let aidParam = (!deviceType.call(this) || isQRead.call(this) || isModifiedVersion) ? "&aid=web" : "";

    switch (sourceType) {
        case 'jj':
            return host + '/jj_comment?bid=' + bid + '&cid=' + cid + '&para=' + para + aidParam;
        case 'qm':
            return host + '/qm_comment?item_id=' + cid + '&book_id=' + bid + '&paragraph_id=' + para + aidParam;
        case 'fq':
        default:
            return host + '/idea_comment?item_id=' + cid + '&book_id=' + bid + '&para=' + para + '&sessionid=' + getSessionId.call(this) + aidParam;
    }
}

