function buildChapterUrl(x, catalog, device) {
    let {
        java
    } = this;
    const isFanqieApp = ['番茄小说', '番茄短剧', '番茄听书', '番茄畅听'].includes(catalog.source);
    const urlToMatch = x.url || catalog.url;
    const bookId = urlToMatch.match(/book_id=(\d{19})\b/)?.[1] || null;
    const itemId = urlToMatch.match(/item_id=(\d+)/)?.[1] || null;
    let contentUrlParams = `chapter?cid=${x.cid}&source=${catalog.source}&device=${device}`;
    if (!isFanqieApp) {
        contentUrlParams += `&url=${catalog.url}`;
    } else {
        contentUrlParams += `&book_id=${bookId}&item_id=${itemId}`;
        if (['番茄听书', '番茄畅听'].includes(catalog.source)) {
            const toneId = Number((this.source.getLoginInfoMap())['听书AI音色编号']) || 1;
            contentUrlParams += `&tone_id=${toneId}`;
        }
    }
    if (catalog.source == '七猫') {
        const qmBookId = x.url.match(/book_id=(\d+)/)?.[1] || null;
        const qmChapterId = x.url.match(/item_id=(\d+)/)?.[1] || null;
        contentUrlParams += `&${x.url}`;
        if (qmBookId && qmChapterId) {
            const qmCommentUrl = `${getServerHost.call(this)}/qm_comment?book_id=${qmBookId}&item_id=${qmChapterId}`;
            return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},{"type":"qingci","js":"book ? result : '${qmCommentUrl}'"}`;
        } else {
            return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},{"type":"qingci"}`;
        }
    } else {
        let commentPart = '{"type":"qingci"}';
        if (catalog.source == '晋江') {
            const novelIdMatch = x.url.match(/novelId=(\d+)/);
            const chapterIdMatch = x.url.match(/chapterId=(\d+)/);
            if (novelIdMatch && chapterIdMatch) {
                const novelId = novelIdMatch[1];
                const chapterId = chapterIdMatch[1];
                const jjCommentUrl = `${getServerHost.call(this)}/jj_comment?novelId=${novelId}&chapterId=${chapterId}`;
                commentPart = `{"type":"qingci","js":"book ? result : '${jjCommentUrl}'"}`;
            }
        } else if (catalog.source == '番茄小说') {
            const fanqieCommentUrl = `${getServerHost.call(this)}/comment?sessionid=${getSessionId.call(this)}&item_id=${itemId}&book_id=${bookId}`;
            commentPart = `{"type":"qingci","js":"book ? result : '${fanqieCommentUrl}'"}`;
        } else if (catalog.source == '云端') {
            const decodedUrl = java.base64Decode(catalog.url);
            const commentUrl = decodedUrl.replace('share', 'comment');
            commentPart = `{"type":"qingci","js":"book ? result : '${commentUrl}&pt=3g'"}`;
        }
        return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},${commentPart}`;
    }
}

