                        selectedItems = "";
                    } else {
                        if (selectedItems.startsWith('">')) {
                            selectedItems = selectedItems.substring(2);
                        } else if (selectedItems.startsWith('>')) {
                            selectedItems = selectedItems.substring(1);
                        }
                    }
                }
            }
        }

        java.put("sortkey", selectedItems);

        if (selectedItems === "") {
            java.toast("已清除所有筛选条件");
        } else {
            java.toast("设置成功，该设置仅🍅番茄小说发现页生效");
        }

    } catch(e) {
        java.log(e);
    }
}

