<js>
const tomatoSources = ["番茄小说", "番茄听书", "番茄畅听"];

if (tomatoSources.includes("{{$.source}}")) {
    try {
        let bookId = getBookIdFromUrl(baseUrl);
        if (bookId) {
            let bookData = getBookData(bookId);

            if (bookData && bookData.tomato_book_status !== '3') {
                // 检查同步开关状态，只有开启时才执行同步
                let syncStatus = java.get("book_sync") ?? "off";
                if (syncStatus == "on") {
                    syncReadingHistory(bookData.book_id);
                }

                let bookName = bookData.original_book_name || bookData.book_name || "";
                let aliasName = bookData.book_flight_alias_name || bookData.sub_title || "";
                let createTime = bookData.create_time ? bookData.create_time.split('T')[0] : "";
                let updateTime = bookData.last_chapter_update_time ? java.timeFormat(parseInt(bookData.last_chapter_update_time)*1000) : "";

                let authors = [];
                try {
                    authors = bookData.original_authors ? JSON.parse(bookData.original_authors) : [];
                } catch(e) {
                    authors = bookData.roles ? bookData.roles.replace(/[\[\]"]/g,'').split(',') : [];
                }
                let authorName = authors.length > 0 ? (authors[0].AuthorName || authors[0] || "") : "";

                let tags = bookData.pure_category_tags || bookData.tags || "";
                let readCount = bookData.read_count || "0";
                let score = bookData.score || "0";
                let last_chapter_title = bookData.last_chapter_title || "暂无";
                let creation_status = bookData.creation_status || "未知";

                let bookStatus = "正常";
                if (bookData.book_search_visible == 'false') {
                    bookStatus = "下架";
                } else if (bookData.tomato_book_status == '3') {
                    bookStatus = "小黑屋";
                }

                let abstract = bookData.book_abstract_v2 || bookData.abstract || "";
                let copyrightInfo = bookData.copyright_info || "";

                let output = `&nbsp;&nbsp;
✨ 源站：{{$.source}}{{"\n"+"​"}}
📕 源名：${bookName}`;

                if (aliasName) {
                    output += `\n📖 别名：${aliasName}`;
                }

                output += `\n✏️ 开坑：${createTime} 
🧭 更新：${updateTime}&lrm;
👤 作者：${authorName}
⭐ 评分:  ${score}分
📖 状态:  连载${creation_status}完结
🏷️ 标签：${tags}
✅ 最新章节: ${last_chapter_title}
👁️ 在线：${readCount}人在读
🔗 书籍状态：${bookStatus}`;

                // 显示同步状态
                output += `\n🔄 阅读记录：${syncStatus == "on" ? "✅已开启同步" : "❌已关闭同步"}`;

                if (["番茄听书"].includes("{{$.source}}")) {
                    try {
                        let tones = "\n===================\n🎧AI音色编号信息: ";
                        let info = JSON.parse(java.ajax(`https://reading.snssdk.com/reading/bookapi/audio/toneinfo/?book_id=${bookData.book_id}&aid=1967`));
                        for (let i of (info.data.tts_tones ? info.data.tts_tones : [])) {
                            tones += `\n${i.id} - ${i.title}${i.description ? "(" + i.description + ")" : ""}`;
                        }
                        output += tones;
                    } catch (e) {
                    }
                }

                output += `{{"\n"+"​"}}
📜 简介：${abstract}{{"\n"+"​"}}`;

                if (copyrightInfo) {
                    output += `\n📍 ${copyrightInfo.split('，')[0]}。`;
                }

                result = output;
            }
        }
    } catch (e) {
    }
}
result;
