 setHeaders("cookie="+encodeURIComponent(co));
	}catch(e){
		java.longToast("你登录好像没有点✓\n请重新进登录网页，登录后点✓");
		}

	}

function toLcf(type,mid){
	let url,name,data,aid;
    try{	
       let info = source.getLoginInfoMap();
       let csrf = String(cookie.getKey("https://www.bilibili.com","bili_jct"));
       let b64 = chapter?chapter.url:"";
       let aid = b64?this.b64D(b64).split("&")[0]:"";
       let isLcy = Number(cache.get(type));

       switch(type){
       	      case "like":
       	           isLcy = isLcy==1?2:1       	            
       	           url = "https://api.bilibili.com/x/web-interface/archive/like,"+JSON.stringify({
                          "method":"POST",
                          "body":"aid="+aid+"&like="+isLcy+"&csrf="+ csrf
                      });
                      data = java.ajax(url);
                      code = JSON.parse(data).code;
                      if(code == 0){
                      	   if(isLcy == 2){
                      	   	    info["👍🏻 点赞"] = "👍🏻 点赞";
                      	   	    java.toast("已取消点赞");
                      	   	    cache.put(type,0,300)
                      	   	}else if(isLcy == 1){
                      	   		   info["👍🏻 点赞"] = "👍🏻 已点赞";
                                        java.toast("已点赞");
                                        cache.put(type,1,300)
                       		}
                      }else if(code == 65004){
                      	   	    code = JSON.parse(java.ajax(url.replace(/like=2/,'like=1'))).data.code;
                      	   	    if(code == 0){
                      	   	    	    java.toast("已点赞");
                                             cache.put(type,1,300)
                      	   	    	}
                       }else if(code == 65006){
                      	   	    code = JSON.parse(java.ajax(url.replace(/like=1/,'like=2'))).data.code;
                      	   	    if(code == 0){
                      	   	    	    java.toast("已取消点赞");
                                             cache.put(type,0,300)
                      	   	    	}
                         }else{
                               java.toast(JSON.parse(data).message)
                         }
       	      break
       	      case "coin":
                     url = "https://api.bilibili.com/x/web-interface/coin/add,"+JSON.stringify({
                          "method":"POST",
                          "body":"multiply=1&del_media_ids=&aid="+aid+"&csrf="+ csrf
                          });
                      if(isLcy==2){
                          java.toast("该视频已达投币上限")
                      }else{
                          data = java.ajax(url);
                          code = JSON.parse(data).code;
                          if(code == 0){
                                isLcy += 1;
                                info["🪙 投币"] = "🪙 已投"+isLcy+"枚";
                                java.toast("成功投币1枚");
                                cache.put(type,isLcy,300)
                          }else{
                              java.toast(JSON.parse(data).message)
                          }
                      }
       	      break
       	      case "fav":
                       let n = isLcy ==1?"add_media_ids=&del_media_ids=0":"add_media_ids=0&del_media_ids=";

              	     url = "https://api.bilibili.com/medialist/gateway/coll/resource/deal,"+JSON.stringify({
                          "method":"POST",
                          "body":n+"&rid="+aid+"&type=2"+"&csrf="+ csrf
                          });
                      data = java.ajax(url);
                      code = JSON.parse(data).code;
                      if(code == 0){
                          if(isLcy == 0){
                               info["⭐️ 收藏"] = "⭐️ 已收藏"
                      	     java.toast("已收藏至默认收藏夹");
                      	     cache.put(type,1,300)
                          }else if(isLcy == 1){
                               info["⭐️ 收藏"] = "⭐️ 收藏"
                      	     java.toast("已从默认收藏夹取消");
                      	     cache.put(type,0,300)
                         }
                      }else{
                          java.toast(JSON.parse(data).message)
                      }
                     break;
                     case "all":
                         url = "https://api.bilibili.com/x/web-interface/archive/like/triple,"+JSON.stringify({
                             "method":"POST",
                             "body":"aid="+aid+"&csrf="+csrf
                         });
                         data = java.ajax(url);
                         code = JSON.parse(data).code;
                         if(code == 0){
                             info["👍🏻 点赞"] = "👍🏻 已点赞"
                             info["⭐️ 收藏"] = "⭐️ 已收藏"
                             info["🪙 投币"] = "🪙 已投2枚"
                             java.toast("👍🏻🪙⭐️一键三连成功")
                         }else{
                             java.toast(JSON.parse(data).message)
                         }
                     break;

                     case "up":
                          isLcy = isLcy==1?2:1;
                          url = "https://api.bilibili.com/x/relation/modify,"+JSON.stringify({
                          "method":"POST",
                          "body":"fid="+mid+"&act="+isLcy+"&csrf="+ csrf
                      });
                      data = java.ajax(url);
                      code = JSON.parse(data).code;
                      if(code == 0){
                          if(isLcy == 1){
                               info["🆙 关注"] = "🆙 已关注"
                      	     java.toast("已关注至默认分组");
                      	     cache.put(type,1,300)
                          }else if(isLcy == 2){
                               info["🆙 关注"] = "🆙 关注"
                      	     java.toast("已从默认分组取消关注");
                      	     cache.put(type,0,300)
                         }
                      }else{
                          java.toast(JSON.parse(data).message)
                      }
                         break
       	}
           java.upLoginData(info)
         }catch(e){
             java.log(e)

         }

	}

