      <Representation bandwidth="1000000">
        <BaseURL></BaseURL>
        <SegmentBase indexRangeExact="true">
          <Initialization sourceURL=""/>
        </SegmentBase>
      </Representation>
    </AdaptationSet>
  </Period>
</MPD>
`;

    }
}

