// 当前书源版本号，切勿修改，否则影响更新的识别
const localVersion = '5.2.03';
let controlUrl = host[0];
function login(flag) {
    if (flag == undefined) {
        result = JSON.parse(source.getLoginInfo())
    } else {
        java.longToast("\n\n💞正在登录中...")
        putLoginInfo(JSON.stringify(result))
    }
    let base_url = getArgument('server')
    let zdyserver = String(result['自定义服务器(可不填)']);
    if (zdyserver.includes('http')) {
        setArgument('server', zdyserver);
        if (getKey(String(cookie.getCookie(base_url)))) {
            let cookies = cookie.getCookie(base_url)
try{cookie.removeCookie(base_url)} catch(e){}
            cookie.setCookie(zdyserver, cookies)
        }
        java.toast(`\n\n当前服务器为自定义服务器\n${zdyserver}\n\n切换服务器请先清空服务器地址中的数据`);
    }
    let plcolor = String(getArgument('plcolor')  || result['自定义评论颜色(可不填)'] || '#000000');
    if (plcolor) {
        setArgument('plcolor', plcolor);
    } else {
        setArgument('plcolor', '#000000');
    }
    let zdysources = String(result['自定义搜索源(多个用英文,分割)'] || '');
    if (zdysources) {
        setArgument('sources', zdysources);
    };
    base_url = getArgument('server')
    let register_email = String(result['邮箱'])
    let password = String(result['密码'])
    let key = String(result['密钥'] || '')

    if ((register_email && password || key) && !String(getKey(String(cookie.getCookie(base_url))))) {
        try{cookie.removeCookie(base_url)} catch(e){}
        let deviceKey = '';
        try {
            deviceKey = java.deviceID();
        } catch (e) {
            deviceKey = java.androidId();
        };
        let deviceId = deviceKey;
        if (register_email && password) {
            let options = JSON.stringify({
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    register_email: result['邮箱'],
                    password: result['密码']
                })
            })
            try {
                let data = JSON.parse(java.ajax(`${base_url}/login_api,${options}`))
                if (data.code == 0) {
                    //java.toast(deviceId)
                    java.toast("\n\n✅️登录成功")
                    cookie.setCookie(base_url, `qttoken=${data.key};deviceId=${deviceId}`)
                    result['密钥'] = data.key
                    setArgument('qttoken', data.key);
                    putLoginInfo(JSON.stringify(result))
                } else {
                    java.toast('\n\n💔' + data.msg || "登录失败，请重试！")
                }
            } catch (e) {
                java.toast("\n\n💔登录失败，请重试！\n" + e.message)
            }
        } else {
            cookie.setCookie(base_url, `qttoken=${key};deviceId=${deviceId}`)
            let res = java.ajax(`${base_url}/user_api,{"method":"POST","headers":{"cookie":"${cookie.getCookie(base_url)}"}}`)
            try {
                res = JSON.parse(res)
                if (res.id != undefined) {
                    setArgument('qttoken', key);
                    java.toast('\n\n密钥登录成功')
                    result['邮箱'] = res.email
                    putLoginInfo(JSON.stringify(result))
                } else {
                    throw new Error()
                }
            } catch (e) {
                java.log(e)
                java.toast("\n\n💔登录失败")
            }
        }
    } else if (flag && String(getKey(String(cookie.getCookie(base_url))))) {
        java.toast("\n\n当前✅️已登录，请🚫退出登录后重新登录");
        //checkStatus();
    } else if (flag) {
        java.toast("\n\n⛔️请先填写邮箱和密码");
    }
}

function objectToCookieString(obj) {
  if (!obj || typeof obj !== 'object') {
    return '';
  }
  return Object.entries(obj)
    .map(([key, value]) => {
      const stringValue = String(value);
      const encodedKey = encodeURIComponent(key);
      const encodedValue = encodeURIComponent(stringValue);
      return `${encodedKey}=${encodedValue}`;
    })
    .join('; ');
}

function control(){
    controlUrla = getArgument('controlUrl');
    if (controlUrla){
        controlUrla = findFirstAvailableHost([controlUrla]);
    }
    if (!controlUrla) {
        controlUrla = findFirstAvailableHost(host) || controlUrl;
    }
    setArgument('controlUrl', controlUrla);
    try {
    	let open_argument = source.getVariable();
    	open_argument=JSON.parse(open_argument);
    	let control_cookie = objectToCookieString(open_argument);
    cookie.setCookie(controlUrla, control_cookie);
    	} catch{}
      //java.toast(cookie.getCookie(controlUrla))
    	java.startBrowserAwait(controlUrla + '/control', '晴天小说设置');
    applyCookieSettings();
	}

function applyCookieSettings() {
	  let controlUrla = getArgument('controlUrl') || controlUrl;
	  	var cookieStr = String(cookie.getCookie(controlUrla));

    var cookieData = {};
    if (cookieStr && cookieStr !== 'null' && cookieStr !== 'undefined' && cookieStr !== '') {
        var pairs = cookieStr.split('; ');
        for (var i = 0; i < pairs.length; i++) {
            var pair = pairs[i];
            var eqIndex = pair.indexOf('=');
            if (eqIndex > -1) {
                var key = pair.substring(0, eqIndex).trim();
                var value = decodeURIComponent(pair.substring(eqIndex + 1).trim());
                cookieData[key] = value;
                setArgument(key, value);
            }
        }
    }

    var displayConfig = [
        { key: 'server', label: '服务器', defaultValue: host[0] },
        { key: 'proxy', label: '访问模式', defaultValue: '云端' },
        { key: 'tab', label: '阅读模式', defaultValue: '小说' },
        { key: 'source_type', label: '阅读频道', defaultValue: '男频' },
        { key: 'sources', label: '书源选择', defaultValue: '全部' },
        { key: 'fqpara', label: '段评显示', defaultValue: 'on' },
        { key: 'disabled_sources', label: '强制搜索', defaultValue: '0' },
        { key: 'reading', label: '同步书架', defaultValue: '0' },
